#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int S[N], votes[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &S[i]);
            votes[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (i != j) {
                    int sum = 0;
                    for (int k = min(i, j) + 1; k < max(i, j); k++) {
                        sum += S[k];
                    }
                    if (S[j] >= sum) {
                        votes[i]++;
                    }
                }
            }
        }
        for (int i = 0; i < N; i++) {
            printf("%d ", votes[i]);
        }
        printf("\n");
    }
    return 0;
}

