import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] S = new int[N];
            int[] votes = new int[N];
            for (int i = 0; i < N; i++) {
                S[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (i != j) {
                        int sum = 0;
                        for (int k = Math.min(i, j) + 1; k < Math.max(i, j); k++) {
                            sum += S[k];
                        }
                        if (S[j] >= sum) {
                            votes[i]++;
                        }
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                System.out.print(votes[i] + " ");
            }
            System.out.println();
        }
    }
}

