const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const S = readline().split(' ').map(x => parseInt(x));
    const votes = new Array(N).fill(0);
    for (let j = 0; j < N; j++) {
        for (let k = 0; k < N; k++) {
            if (j !== k) {
                let sum = 0;
                for (let l = Math.min(j, k) + 1; l < Math.max(j, k); l++) {
                    sum += S[l];
                }
                if (S[k] >= sum) {
                    votes[j]++;
                }
            }
        }
    }
    console.log(votes.join(' '));
}
